%% P2_Exp10_attention_pooling_summary_plots.m
% Purpose:
% This script summarizes and visualizes attention-pooling ablation results
% for target-domain pack-level SOH prediction. It reads prediction and
% maximum-attention-score results generated by P2_Exp07 for soft-min,
% standard attention, hard-min, and mean pooling, and generates summary plots
% for the associated Extended Data figure.

clc; clear; close all;

%% 1) Configuration
cfg = struct();

% Use the script folder as the project root.
script_dir = fileparts(mfilename('fullpath'));

if isempty(script_dir)
    script_dir = pwd;
end

cfg.output_results_dir = fullfile(script_dir, 'Output', 'Results');
cfg.figure_dir = fullfile(script_dir, 'Figures', 'Extended');

% Input files generated by Main07.
cfg.softmin_csv = fullfile(cfg.output_results_dir, 'P2_Exp07_AttentionPoolingAblation_Softmin_PackPredictions.csv');
cfg.standard_csv = fullfile(cfg.output_results_dir, 'P2_Exp07_AttentionPoolingAblation_Standard_PackPredictions.csv');
cfg.hardmin_csv = fullfile(cfg.output_results_dir, 'P2_Exp07_AttentionPoolingAblation_Hardmin_PackPredictions.csv');
cfg.mean_csv = fullfile(cfg.output_results_dir, 'P2_Exp07_AttentionPoolingAblation_Mean_PackPredictions.csv');

% Output figures.
cfg.fig_tracking = fullfile(cfg.figure_dir,  'ExD01i_attention_tracking.fig');
cfg.png_tracking = fullfile(cfg.figure_dir, 'ExD01i_attention_tracking.png');

cfg.fig_error_heatmap = fullfile(cfg.figure_dir, 'ExD01j_attention_error_heatmap.fig');
cfg.png_error_heatmap = fullfile(cfg.figure_dir, 'ExD01j_attention_error_heatmap.png');

cfg.fig_attn_heatmap = fullfile(cfg.figure_dir, 'ExD01k_max_attention_heatmap.fig');
cfg.png_attn_heatmap = fullfile(cfg.figure_dir, 'ExD01k_max_attention_heatmap.png');

cfg.png_resolution = 600;

if ~exist(cfg.figure_dir, 'dir')
    mkdir(cfg.figure_dir);
end

fprintf('================ P2 Exp10: Attention-pooling summary plots ================\n');

%% 2) Load attention-ablation prediction results
T_softmin  = local_read_required_table(cfg.softmin_csv);
T_standard = local_read_required_table(cfg.standard_csv);
T_hardmin  = local_read_required_table(cfg.hardmin_csv);
T_mean     = local_read_required_table(cfg.mean_csv);

pack_idx_raw = local_get_numeric_col(T_softmin, {'Pack_Index', 'Sample_Index', 'Index'});
true_soh_raw = local_get_numeric_col(T_softmin, {'True_SOH', 'True_Pack_SOH'});

pred_softmin_raw = local_get_numeric_col(T_softmin, {'Predicted_SOH', 'Pred_Softmin'});
err_softmin_raw  = local_get_numeric_col(T_softmin, {'Error'});
attn_softmin_raw = local_get_numeric_col(T_softmin, {'Max_Attention_Score', 'MaxAttn'});

pred_standard_raw = local_read_aligned_col(T_standard, pack_idx_raw, {'Predicted_SOH', 'Pred_Standard'});
err_standard_raw  = local_read_aligned_col(T_standard, pack_idx_raw, {'Error'});
attn_standard_raw = local_read_aligned_col(T_standard, pack_idx_raw, {'Max_Attention_Score', 'MaxAttn'});

pred_hardmin_raw = local_read_aligned_col(T_hardmin, pack_idx_raw, {'Predicted_SOH', 'Pred_Hardmin'});
err_hardmin_raw  = local_read_aligned_col(T_hardmin, pack_idx_raw, {'Error'});
attn_hardmin_raw = local_read_aligned_col(T_hardmin, pack_idx_raw, {'Max_Attention_Score', 'MaxAttn'});

pred_mean_raw = local_read_aligned_col(T_mean, pack_idx_raw, {'Predicted_SOH', 'Pred_Mean'});
err_mean_raw  = local_read_aligned_col(T_mean, pack_idx_raw, {'Error'});
attn_mean_raw = local_read_aligned_col(T_mean, pack_idx_raw, {'Max_Attention_Score', 'MaxAttn'});

% Sort packs by true SOH in descending order.
[true_soh, sort_idx] = sort(true_soh_raw, 'descend');

pack_idx = (1:numel(true_soh))';

pred_softmin  = pred_softmin_raw(sort_idx);
pred_standard = pred_standard_raw(sort_idx);
pred_hardmin  = pred_hardmin_raw(sort_idx);
pred_mean     = pred_mean_raw(sort_idx);

err_softmin  = err_softmin_raw(sort_idx);
err_standard = err_standard_raw(sort_idx);
err_hardmin  = err_hardmin_raw(sort_idx);
err_mean     = err_mean_raw(sort_idx);

attn_softmin  = attn_softmin_raw(sort_idx);
attn_standard = attn_standard_raw(sort_idx);
attn_hardmin  = attn_hardmin_raw(sort_idx);
attn_mean     = attn_mean_raw(sort_idx);

err_matrix = abs([ ...
    err_softmin, ...
    err_standard, ...
    err_hardmin, ...
    err_mean])';

attn_matrix = [ ...
    attn_softmin, ...
    attn_standard, ...
    attn_hardmin, ...
    attn_mean]';

labels = {'Softmin (Ours)', 'Standard', 'Hardmin', 'Mean'};

fprintf('Loaded attention-ablation results for %d packs.\n', numel(true_soh));
fprintf('  - Softmin:  %s\n', cfg.softmin_csv);
fprintf('  - Standard: %s\n', cfg.standard_csv);
fprintf('  - Hardmin:  %s\n', cfg.hardmin_csv);
fprintf('  - Mean:     %s\n', cfg.mean_csv);

%% 3) Panel I: SOH prediction trajectories
fig_tracking = figure( ...
    'Name', 'P2_Exp10_AttentionPoolingTracking', ...
    'Position', [100, 450, 800, 500], ...
    'Color', 'w');

plot(pack_idx, true_soh, 'k', 'LineWidth', 2.5);
hold on;

plot(pack_idx, pred_softmin, 'r-p', ...
    'LineWidth', 1.5, ...
    'MarkerSize', 8, ...
    'MarkerEdgeColor', 'k', ...
    'MarkerFaceColor', 'r');

plot(pack_idx, pred_hardmin, 'm--o', ...
    'LineWidth', 1.5, ...
    'MarkerSize', 5, ...
    'MarkerEdgeColor', 'k', ...
    'MarkerFaceColor', 'm');

plot(pack_idx, pred_standard, 'b-.<', ...
    'LineWidth', 1.5, ...
    'MarkerSize', 5, ...
    'MarkerEdgeColor', 'k', ...
    'MarkerFaceColor', 'b');

plot(pack_idx, pred_mean, 'g--s', ...
    'LineWidth', 1.5, ...
    'MarkerSize', 5, ...
    'MarkerEdgeColor', 'k', ...
    'MarkerFaceColor', 'g');

legend('True SOH', 'Ours (Softmin)', 'Hardmin', 'Standard', 'Mean', ...
    'NumColumns', 3, ...
    'Location', 'SouthWest');

xlabel('Pack index');
ylabel('SOH');

set(gca, ...
    'FontSize', 14, ...
    'FontName', 'Times New Roman', ...
    'TickDir', 'in');

box on;
grid on;
set(gca, 'GridAlpha', 0.3);

xlim([0, max(pack_idx) + 1]);

y_min = min([true_soh; pred_softmin; pred_hardmin; pred_standard; pred_mean]) - 0.01;
y_max = max([true_soh; pred_softmin; pred_hardmin; pred_standard; pred_mean]) + 0.01;
ylim([y_min, y_max]);

local_save_figure(fig_tracking, ...
    cfg.fig_tracking, ...
    cfg.png_tracking, ...
    cfg.png_resolution);

%% 4) Define colormaps for heatmaps
n1 = 128;
n2 = 128;

r1 = [0.98 0.92 0.92];
r2 = [0.98 0.6 0.5];
r3 = [0.65 0.05 0.15];

cmap_reds = [ ...
    linspace(r1(1), r2(1), n1)', linspace(r1(2), r2(2), n1)', linspace(r1(3), r2(3), n1)'; ...
    linspace(r2(1), r3(1), n2)', linspace(r2(2), r3(2), n2)', linspace(r2(3), r3(3), n2)'];

p1 = [0.95 0.93 0.98];
p2 = [0.8 0.7 0.9];
p3 = [0.3 0.05 0.5];

cmap_purples = [ ...
    linspace(p1(1), p2(1), n1)', linspace(p1(2), p2(2), n1)', linspace(p1(3), p2(3), n1)'; ...
    linspace(p2(1), p3(1), n2)', linspace(p2(2), p3(2), n2)', linspace(p2(3), p3(3), n2)'];

%% 5) Panel J: Absolute-error heatmap
fig_error_heatmap = figure( ...
    'Name', 'P2_Exp10_AttentionPoolingErrorHeatmap', ...
    'Position', [950, 650, 750, 250], ...
    'Color', 'w');

imagesc(pack_idx, 1:4, err_matrix);
colormap(gca, cmap_reds);

cb1 = colorbar;
cb1.Label.String = 'Absolute error';
cb1.Label.FontWeight = 'bold';

hold on;

for i = 0.5:1:max(pack_idx)+0.5
    plot([i, i], [0.5, 4.5], 'w-', 'LineWidth', 0.1);
end

for j = 0.5:1:4.5
    plot([0.5, max(pack_idx)+0.5], [j, j], 'w-', 'LineWidth', 0.1);
end

yticks(1:4);
yticklabels(labels);

xlabel('Pack index (sorted by true SOH)', ...
    'FontWeight', 'bold', ...
    'FontSize', 12);

set(gca, ...
    'FontWeight', 'bold', ...
    'TickDir', 'out', ...
    'LineWidth', 1.2);

xlim([0.5, max(pack_idx)+0.5]);
ylim([0.5, 4.5]);

local_save_figure(fig_error_heatmap, ...
    cfg.fig_error_heatmap, ...
    cfg.png_error_heatmap, ...
    cfg.png_resolution);

%% 6) Panel K: Attention-score heatmap
fig_attn_heatmap = figure( ...
    'Name', 'P2_Exp10_MaxAttentionScoreHeatmap', ...
    'Position', [950, 300, 750, 250], ...
    'Color', 'w');

imagesc(pack_idx, 1:4, attn_matrix);
colormap(gca, cmap_purples);

cb2 = colorbar;
cb2.Label.String = 'Maximum attention score';
cb2.Label.FontWeight = 'bold';

hold on;

for i = 0.5:1:max(pack_idx)+0.5
    plot([i, i], [0.5, 4.5], 'w-', 'LineWidth', 0.5);
end

for j = 0.5:1:4.5
    plot([0.5, max(pack_idx)+0.5], [j, j], 'w-', 'LineWidth', 0.5);
end

yticks(1:4);
yticklabels(labels);

xlabel('Pack index (sorted by true SOH)', ...
    'FontWeight', 'bold', ...
    'FontSize', 12);

set(gca, ...
    'FontWeight', 'bold', ...
    'TickDir', 'out', ...
    'LineWidth', 1.2);

xlim([0.5, max(pack_idx)+0.5]);
ylim([0.5, 4.5]);

local_save_figure(fig_attn_heatmap, ...
    cfg.fig_attn_heatmap, ...
    cfg.png_attn_heatmap, ...
    cfg.png_resolution);

fprintf('\n>>> Attention-pooling figures completed.\n');
fprintf('>>> Saved panel I: %s\n', cfg.png_tracking);
fprintf('>>> Saved panel J: %s\n', cfg.png_error_heatmap);
fprintf('>>> Saved panel K: %s\n', cfg.png_attn_heatmap);


%% Local helper functions
function T = local_read_required_table(filename)
% Read a required CSV table.

if ~isfile(filename)
    error('File not found: %s', filename);
end

T = readtable(filename, 'VariableNamingRule', 'preserve');
end

function x = local_get_numeric_col(T, candidates)
% Extract a numeric column from a table using candidate column names.

vars = T.Properties.VariableNames;
col = local_find_col(vars, candidates);

if isempty(col)
    disp(vars');
    error('Required column not found. Candidate names: %s', strjoin(candidates, ', '));
end

x = T.(col);

if iscell(x) || isstring(x) || ischar(x)
    x = str2double(string(x));
end

x = double(x);
x = x(:);
end

function y = local_read_aligned_col(T, pack_idx_ref, candidates)
% Read one numeric column from a table and align it by Pack_Index.

pred = local_get_numeric_col(T, candidates);

vars = T.Properties.VariableNames;
idx_col = local_find_col(vars, {'Pack_Index', 'Sample_Index', 'Index'});

if isempty(idx_col)

    if height(T) ~= numel(pack_idx_ref)
        error('Pack_Index was not found, and row numbers are inconsistent.');
    end

    y = pred(:);
    return;
end

idx = local_get_numeric_col(T, {'Pack_Index', 'Sample_Index', 'Index'});

[tf, loc] = ismember(pack_idx_ref, idx);

if any(~tf)
    error('Some Pack_Index values were not found in the target table.');
end

y = pred(loc);
y = y(:);
end

function col = local_find_col(vars, candidates)
% Find a column by matching normalized column names.

col = '';

vars_norm = cell(size(vars));

for i = 1:numel(vars)
    vars_norm{i} = local_normalize_name(vars{i});
end

for i = 1:numel(candidates)

    cand_norm = local_normalize_name(candidates{i});
    idx = find(strcmp(vars_norm, cand_norm), 1);

    if ~isempty(idx)
        col = vars{idx};
        return;
    end
end
end

function s = local_normalize_name(s)
% Normalize column names for robust matching.

s = char(s);
s = lower(s);
s = regexprep(s, '[^a-z0-9]', '');
end

function local_save_figure(fig_handle, fig_file, png_file, resolution)
% Save a figure as both FIG and PNG files.

out_dir = fileparts(fig_file);

if ~exist(out_dir, 'dir')
    mkdir(out_dir);
end

savefig(fig_handle, fig_file);
exportgraphics(fig_handle, png_file, 'Resolution', resolution);

fprintf('[Figure] Saved: %s\n', png_file);
end